                        return apiResponseLocalVar;
                    }
                }
            }
            catch(Exception e)
            {
                OnErrorCreateCustomViewManagementDefaultImplementation(e, "/obp/v6.0.0/management/banks/{bankid}/accounts/{accountid}/views", uriBuilderLocalVar.Path, bankid, accountid, createCustomViewManagementRequest);
                Events.ExecuteOnErrorCreateCustomViewManagement(e);
                throw;
            }
        }

