                        ILogger<AccountApi.GetViewsForBankAccountApiResponse> apiResponseLoggerLocalVar = LoggerFactory.CreateLogger<AccountApi.GetViewsForBankAccountApiResponse>();
                        AccountApi.GetViewsForBankAccountApiResponse apiResponseLocalVar;

                        switch ((int)httpResponseMessageLocalVar.StatusCode) {
