        /// </summary>
        /// <param name="bankid">The BANKID identifier</param>
        /// <param name="accountid">The ACCOUNTID identifier</param>
        /// <param name="viewid">The VIEWID identifier</param>
        /// <param name="updateViewForBankAccountRequest">Request body</param>
        /// <param name="cancellationToken">Cancellation Token to cancel the request.</param>
        /// <returns><see cref="Task"/>&lt;<see cref="IUpdateViewForBankAccountApiResponse"/>&gt;</returns>
        public async Task<IUpdateViewForBankAccountApiResponse?> UpdateViewForBankAccountOrDefaultAsync(string bankid, string accountid, string viewid, UpdateViewForBankAccountRequest updateViewForBankAccountRequest, System.Threading.CancellationToken cancellationToken = default)
        {
            try
            {
                return await UpdateViewForBankAccountAsync(bankid, accountid, viewid, updateViewForBankAccountRequest, cancellationToken).ConfigureAwait(false);
            }
            catch (Exception)
            {
                return null;
            }
        }

